<?php namespace App\Services; use Illuminate\Support\Facades\Crypt; use Illuminate\Contracts\Encryption\DecryptException; use Illuminate\Support\Facades\Log; class SecurityService { public function encryptData(mixed $value): string { try { return Crypt::encryptString(serialize($value)); } catch (\Exception $e) { Log::error('Encryption failure: ' . $e->getMessage()); throw $e; } } public function decryptData(string $encryptedValue): mixed { try { return unserialize(Crypt::decryptString($encryptedValue)); } catch (DecryptException $e) { Log::error('Decryption failure: ' . $e->getMessage()); return null; } } public function generateSignature(string $data): string { return hash_hmac('sha256', $data, config('app.key')); } public function verifyData(string $data, string $signature): bool { $expected = $this->generateSignature($data); return hash_equals($expected, $signature); } public function secureJson(array $data): string { return json_encode([ 'payload' => $this->encryptData($data), 'signature' => $this->generateSignature(json_encode($data)) ]); } }